import React, { useState, useEffect } from 'react';

const API = 'http://localhost:5001';

export default function StatusViewer({ token, currentUser, onClose }) {
  const [statuses, setStatuses] = useState([]);
  const [viewing, setViewing] = useState(null); // { username, status }
  const [newText, setNewText] = useState('');
  const [uploading, setUploading] = useState(false);
  const [tab, setTab] = useState('view'); // view | add

  useEffect(() => {
    fetch(API + '/statuses', { headers: { Authorization: `Bearer ${token}` } })
      .then(r => r.json()).then(data => setStatuses(Array.isArray(data) ? data : []));
  }, [token]);

  const postTextStatus = async () => {
    if (!newText.trim()) return;
    setUploading(true);
    const fd = new FormData();
    fd.append('type', 'text');
    fd.append('content', newText);
    await fetch(API + '/status', { method: 'POST', headers: { Authorization: `Bearer ${token}` }, body: fd });
    setUploading(false);
    setNewText('');
    setTab('view');
    // reload
    const res = await fetch(API + '/statuses', { headers: { Authorization: `Bearer ${token}` } });
    const data = await res.json();
    setStatuses(Array.isArray(data) ? data : []);
  };

  const postFileStatus = async (e, type) => {
    const file = e.target.files[0];
    if (!file) return;
    setUploading(true);
    const fd = new FormData();
    fd.append('type', type);
    fd.append('file', file);
    await fetch(API + '/status', { method: 'POST', headers: { Authorization: `Bearer ${token}` }, body: fd });
    setUploading(false);
    setTab('view');
    const res = await fetch(API + '/statuses', { headers: { Authorization: `Bearer ${token}` } });
    const data = await res.json();
    setStatuses(Array.isArray(data) ? data : []);
  };

  const timeAgo = (d) => {
    const diff = Date.now() - new Date(d);
    const h = Math.floor(diff / 3600000);
    const m = Math.floor(diff / 60000);
    if (h > 0) return `${h}h ago`;
    if (m > 0) return `${m}m ago`;
    return 'just now';
  };

  const s = {
    overlay: { position:'fixed', inset:0, background:'rgba(0,0,0,0.8)', display:'flex', alignItems:'center', justifyContent:'center', zIndex:1000 },
    box: { background:'#1e1e2e', border:'1px solid #2d2d3f', borderRadius:16, width:420, maxHeight:'80vh', display:'flex', flexDirection:'column', overflow:'hidden' },
    header: { padding:'16px 20px', borderBottom:'1px solid #2d2d3f', display:'flex', justifyContent:'space-between', alignItems:'center' },
    tabRow: { display:'flex', gap:8, padding:'12px 16px', borderBottom:'1px solid #2d2d3f' },
    tabBtn: (a) => ({ flex:1, padding:'8px', background:a?'#312e81':'transparent', border:'1px solid '+(a?'#4338ca':'#2d2d3f'), borderRadius:8, color:a?'#a5b4fc':'#64748b', fontSize:13, fontWeight:600, cursor:'pointer' }),
    body: { flex:1, overflowY:'auto', padding:'16px' },
    userRow: { display:'flex', alignItems:'center', gap:10, padding:'10px', borderRadius:10, cursor:'pointer', marginBottom:8, background:'#12121a', border:'1px solid #2d2d3f' },
    inp: { width:'100%', padding:'11px 14px', background:'#12121a', border:'1px solid #2d2d3f', borderRadius:10, color:'#e2e8f0', fontSize:14, outline:'none', boxSizing:'border-box', marginBottom:10, resize:'vertical', minHeight:80, fontFamily:'Inter,sans-serif' },
    uploadBtn: { display:'flex', alignItems:'center', gap:8, padding:'10px 16px', background:'#12121a', border:'1px solid #2d2d3f', borderRadius:10, color:'#a5b4fc', fontSize:13, cursor:'pointer', marginBottom:8, fontWeight:500 },
    postBtn: { width:'100%', padding:'11px', background:'linear-gradient(90deg,#6366f1,#8b5cf6)', border:'none', borderRadius:10, color:'#fff', fontWeight:600, fontSize:14, cursor:'pointer', marginTop:4 },
  };

  // full screen status viewer
  if (viewing) {
    const st = viewing.status;
    return (
      <div style={{ ...s.overlay, flexDirection:'column', background:'#000' }}>
        <div style={{ position:'absolute', top:20, left:20, color:'#fff', fontSize:14, fontWeight:600 }}>
          {viewing.username === currentUser.username ? 'My Status' : viewing.username}
        </div>
        <button onClick={() => setViewing(null)} style={{ position:'absolute', top:16, right:20, background:'none', border:'none', color:'#fff', fontSize:24, cursor:'pointer' }}>✕</button>
        <div style={{ maxWidth:500, width:'100%', textAlign:'center', padding:20 }}>
          {st.type === 'text' && <div style={{ fontSize:24, color:'#fff', fontWeight:600, lineHeight:1.5 }}>{st.content}</div>}
          {st.type === 'image' && <img src={st.fileUrl} alt="status" style={{ maxWidth:'100%', maxHeight:'70vh', borderRadius:12 }} />}
          {st.type === 'video' && <video src={st.fileUrl} controls style={{ maxWidth:'100%', maxHeight:'70vh', borderRadius:12 }} />}
          {st.type === 'audio' && <audio src={st.fileUrl} controls style={{ width:'100%' }} />}
          <div style={{ color:'#64748b', fontSize:12, marginTop:12 }}>{timeAgo(st.createdAt)}</div>
        </div>
      </div>
    );
  }

  return (
    <div style={s.overlay}>
      <div style={s.box}>
        <div style={s.header}>
          <div style={{ fontSize:16, fontWeight:700, color:'#e2e8f0' }}>📸 Status</div>
          <button onClick={onClose} style={{ background:'none', border:'none', color:'#64748b', fontSize:20, cursor:'pointer' }}>✕</button>
        </div>
        <div style={s.tabRow}>
          <button style={s.tabBtn(tab==='view')} onClick={() => setTab('view')}>👁 View</button>
          <button style={s.tabBtn(tab==='add')} onClick={() => setTab('add')}>➕ Add Status</button>
        </div>
        <div style={s.body}>
          {tab === 'view' && (
            statuses.length === 0
              ? <div style={{ textAlign:'center', color:'#334155', padding:30 }}>No statuses yet</div>
              : statuses.map(u => (
                <div key={u.username}>
                  <div style={{ fontSize:11, color:'#475569', marginBottom:6, fontWeight:600 }}>
                    {u.username === currentUser.username ? 'My Status' : u.username}
                  </div>
                  <div style={{ display:'flex', gap:8, flexWrap:'wrap', marginBottom:12 }}>
                    {u.statuses.map((st, i) => (
                      <div key={i} onClick={() => setViewing({ username: u.username, status: st })}
                        style={{ width:60, height:60, borderRadius:12, background:'#12121a', border:'2px solid #6366f1', cursor:'pointer', overflow:'hidden', display:'flex', alignItems:'center', justifyContent:'center' }}>
                        {st.type === 'text' && <div style={{ fontSize:10, color:'#c7d2fe', padding:4, textAlign:'center', overflow:'hidden' }}>{st.content.slice(0,20)}</div>}
                        {st.type === 'image' && <img src={st.fileUrl} alt="" style={{ width:'100%', height:'100%', objectFit:'cover' }} />}
                        {st.type === 'video' && <div style={{ fontSize:20 }}>🎬</div>}
                        {st.type === 'audio' && <div style={{ fontSize:20 }}>🎵</div>}
                      </div>
                    ))}
                  </div>
                </div>
              ))
          )}
          {tab === 'add' && (
            <>
              <textarea style={s.inp} placeholder="Write a text status..." value={newText} onChange={e => setNewText(e.target.value)} />
              {newText.trim() && <button style={s.postBtn} onClick={postTextStatus} disabled={uploading}>{uploading ? 'Posting...' : 'Post Text Status'}</button>}
              <div style={{ marginTop:12 }}>
                {[['image','🖼 Photo','.jpg,.jpeg,.png,.gif,.webp'],['video','🎬 Video','.mp4,.mov,.webm'],['audio','🎵 Audio','.mp3,.wav,.ogg,.m4a']].map(([type, label, accept]) => (
                  <label key={type} style={s.uploadBtn}>
                    {label}
                    <input type="file" accept={accept} style={{ display:'none' }} onChange={e => postFileStatus(e, type)} />
                  </label>
                ))}
              </div>
              {uploading && <div style={{ textAlign:'center', color:'#818cf8', fontSize:13, marginTop:8 }}>Uploading...</div>}
            </>
          )}
        </div>
      </div>
    </div>
  );
}
